28	    const premium = quote(step.items, customer, contractNumber);
29	    policiesByStep[i] = step.items;
30	    policyPayouts[i] = 0;
31	    results.push({ premium });
32	    contractNumber++;
33	  } else if (step.op === "claim") {
34	    const policyIndex = step.policy;
35	    const policyItems = policiesByStep[policyIndex];
36	    const previousPayouts = policyPayouts[policyIndex];
37	    const result = claim(policyItems, step.incident.damages, previousPayouts);
38	    policyPayouts[policyIndex] = previousPayouts + result.payout;
39	    results.push({ payout: result.payout, remainingCap: result.remainingCap });
40	  }
41	}
